SELECT DISTINCT d.NAME
FROM (SELECT DISTINCT JOB FROM EMP WHERE ENAME = 'A') e
LEFT JOIN (SELECT DISTINCT NAME FROM DEPT) d ON e.JOB = d.NAME;

SELECT SUM(CAST(f1 * SAL AS INTEGER)) 
FROM (
    SELECT SAL, COUNT(*) AS f1 
    FROM EMP 
    GROUP BY SAL
) AS t;

SELECT * 
FROM emp e1 
WHERE e1.empno > (SELECT MIN(deptno) FROM dept);
